{
  "grammar": [
    {
      "pattern": "Subject + 然後 + Verb Phrase + 呢？",
      "structure": ["Subject", "然後", "Verb Phrase", "呢"],
      "explanation_en": "Use '然後呢' to ask 'And then what happened?' to encourage the speaker to continue the story.",
      "title": "然後呢 (And then?)",
      "meaning": "Asking for the next part of a story",
      "when_to_use": ["When someone is telling a story and pauses", "When you want to show interest and ask for more details"],
      "when_not_to_use": ["When the story is clearly finished", "When you want to ask a specific question about a detail"],
      "pragmatic_notes": "In Taiwan, '然後呢' is very common in casual conversation to keep the story going. It's friendly and shows you're listening.",
      "word_order_notes": "Place '然後呢' at the end of your question, after the subject and verb phrase.",
      "english_contrast": "In English, we say 'And then?' or 'What happened next?' In Chinese, '然後呢' is more concise and natural.",
      "korean_contrast": "In Korean, '그리고 나서?' is similar, but '然後呢' is more direct and common in casual speech.",
      "negative_examples": [
        {
          "text": "然後呢？你昨天去哪裡？",
          "error": "This is not incorrect, but it combines two questions. Better to ask '然後呢？' alone to focus on the story."
        }
      ],
      "incorrect_examples": [
        {
          "text": "你然後呢？",
          "error": "Incorrect word order. '然後呢' should come after the subject and verb phrase, not before."
        }
      ],
      "transformation_drills": [
        "Change '你昨天去哪裡？' to '你昨天去哪裡，然後呢？'"
      ],
      "production_drills": [
        "Ask a friend to continue a story about their weekend using '然後呢'."
      ],
      "common_error_patterns": [
        "Placing '然後呢' at the beginning of a sentence instead of after the subject and verb phrase."
      ],
      "repair_feedback": {
        "word_order": "Put '然後呢' after the subject and verb phrase, not before.",
        "politeness": "This is casual; use with friends or in informal settings.",
        "vocabulary": "Use '然後呢' to ask for the next part of a story."
      }
    },
    {
      "pattern": "Subject + 後來 + Verb Phrase",
      "structure": ["Subject", "後來", "Verb Phrase"],
      "explanation_en": "Use '後來' to mean 'later' or 'afterwards' to indicate a sequence of events in a story.",
      "title": "後來 (Later/Afterwards)",
      "meaning": "Indicating a later event in a story",
      "when_to_use": ["When telling a story and moving to a later point in time", "When describing what happened after a previous event"],
      "when_not_to_use": ["When the event is immediate or simultaneous", "When you want to say 'and then' in a very short sequence"],
      "pragmatic_notes": "In Taiwan, '後來' is very common in storytelling to mark a shift in time. It's neutral and can be used in both formal and informal contexts.",
      "word_order_notes": "Place '後來' after the subject and before the verb phrase.",
      "english_contrast": "In English, we say 'later' or 'afterwards'. In Chinese, '後來' is more specific to narrative sequences.",
      "korean_contrast": "In Korean, '나중에' is similar, but '後來' is more commonly used in storytelling.",
      "negative_examples": [
        {
          "text": "後來我昨天去商店。",
          "error": "Incorrect because '後來' implies a later time, but '昨天' is a specific past time. Use '後來' for a sequence, not a specific time."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我後來去商店昨天。",
          "error": "Incorrect word order. '後來' should come after the subject and before the verb phrase, not at the end."
        }
      ],
      "transformation_drills": [
        "Change '我昨天去商店，然後回家。' to '我昨天去商店，後來回家。'"
      ],
      "production_drills": [
        "Tell a short story about your day using '後來' to connect events."
      ],
      "common_error_patterns": [
        "Using '後來' with a specific time like '昨天' instead of a sequence."
      ],
      "repair_feedback": {
        "word_order": "Put '後來' after the subject and before the verb phrase.",
        "politeness": "Neutral; can be used in any context.",
        "vocabulary": "Use '後來' to indicate a later event in a story."
      }
    },
    {
      "pattern": "Subject + 的 + 意思 + 是 + Question Word + 嗎？",
      "structure": ["Subject", "的", "意思", "是", "Question Word", "嗎"],
      "explanation_en": "Use '你的意思是...嗎？' to ask for clarification or to confirm understanding of what someone said.",
      "title": "你的意思是...嗎？ (Do you mean...?)",
      "meaning": "Asking for clarification or confirmation",
      "when_to_use": ["When you are not sure what someone meant", "When you want to confirm your understanding of a story or statement"],
      "when_not_to_use": ["When you fully understand", "When you want to ask a simple yes/no question about facts"],
      "pragmatic_notes": "In Taiwan, this is a polite way to ask for clarification. It shows you are listening carefully and want to understand correctly.",
      "word_order_notes": "Place '你的意思是' at the beginning, followed by the part you want to clarify, and end with '嗎'.",
      "english_contrast": "In English, we say 'Do you mean...?' In Chinese, '你的意思是...嗎？' is more formal and polite.",
      "korean_contrast": "In Korean, '네 말은...이라는 뜻이야?' is similar, but '你的意思是...嗎？' is more direct.",
      "negative_examples": [
        {
          "text": "你的意思是什麼？",
          "error": "This is correct but less specific. '你的意思是...嗎？' is better for confirming a specific point."
        }
      ],
      "incorrect_examples": [
        {
          "text": "你的意思是你去商店嗎？",
          "error": "This is correct, but if the context is a story, it might be too vague. Better to specify the action."
        }
      ],
      "transformation_drills": [
        "Change '我不明白。' to '你的意思是...嗎？'"
      ],
      "production_drills": [
        "Listen to a short story and ask a clarification question using '你的意思是...嗎？'"
      ],
      "common_error_patterns": [
        "Using '你的意思是' without '嗎' at the end, making it a statement instead of a question."
      ],
      "repair_feedback": {
        "word_order": "Put '你的意思是' at the beginning, the part to clarify in the middle, and '嗎' at the end.",
        "politeness": "Polite and appropriate for any situation.",
        "vocabulary": "Use '你的意思是...嗎？' to ask for clarification."
      }
    }
  ]
}
